  const src = item.json && (
      item.json.parsed_json ?? 
      item.json.output ?? 
      item.json.output_text ?? 
      item.output ?? 
      item.payload
  );

  let parsed = null;

  if (src === undefined || src === null) {
    return {
      json: { _error: "no_output_field_found", original: item.json }
    };
  }

  // 1. PARSE DỮ LIỆU
  if (typeof src === 'object') {
    parsed = src;
  } else {
    parsed = tryParseJsonString(src);
  }

  if (!parsed) {
    return {
      json: { _error: "parse_failed", raw: src }
    };
  }

