  // B. Chuẩn hóa Education (Array)
  if (parsed.filter_education) {
      parsed.filter_education = normalizeList(parsed.filter_education);
  }

  // C. Chuẩn hóa Experience (Math Symbol) [MỚI THÊM]
  if (parsed.filter_experience) {
      parsed.filter_experience = normalizeExperience(parsed.filter_experience);
  }

  // 3. Trả về kết quả
  return { json: parsed };
});

