={{
  (() => {
    // =====================================================================
    // 1. HELPER FUNCTIONS
    // =====================================================================
    function removeAccents(str) {
      if (!str) return "";
      return str.normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/đ/g, "d").replace(/Đ/g, "D").trim();
    }

    function generateMatchClauses(keyword, targetFields) {
        const rawKey = keyword.trim();
        if (!rawKey) return [];
        const variants = [...new Set([rawKey, rawKey.toLowerCase(), removeAccents(rawKey)])];
        const conditions = [];
        targetFields.forEach(field => {
            variants.forEach(v => { 
                conditions.push({ "key": field, "match": { "text": v } }); 
            });
        });
        return conditions;
    }

    // Hàm tạo bộ lọc tên
    function generateNameClauses(nameKeyword) {
        // Xử lý trường hợp input là mảng hoặc null (do AI trả về [null])
        if (!nameKeyword || (Array.isArray(nameKeyword) && nameKeyword[0] === null)) return [];
        const rawName = String(nameKeyword).trim();
        if (rawName === "null" || rawName === "") return [];

        const upperName = rawName.toUpperCase();
        const upperNoAccent = removeAccents(upperName);

        const variants = [...new Set([
            upperName,          // PHONG (Ưu tiên)
            upperNoAccent,
            rawName, 
            removeAccents(rawName)
        ])];

        const conditions = [];
        // Danh sách trường cần quét
        const nameFields = ["candidate_name", "contact_info.name", "name", "text"]; 

        nameFields.forEach(field => {
            variants.forEach(v => {
                conditions.push({ "key": field, "match": { "text": v } });
            });
        });
        return conditions;
    }

    function processLogicFilter(textArray, fields, targetMustArray) {
        if (!textArray) return;
        // Xử lý trường hợp [null] từ AI
        if (Array.isArray(textArray) && textArray[0] === null) return;

        const items = Array.isArray(textArray) ? textArray : [textArray];
        items.forEach(item => {
            if (!item || item === "null" || String(item).length > 150) return;

            if (String(item).match(/\s+(?:hoặc|or)\s+/i)) {
                const parts = String(item).split(/\s+(?:hoặc|or)\s+/i);
                let aggregatedShoulds = [];
                parts.forEach(part => { aggregatedShoulds.push(...generateMatchClauses(part, fields)); });
                if (aggregatedShoulds.length > 0) targetMustArray.push({ "should": aggregatedShoulds });
            } else {
                const parts = String(item).split(/\s*(?:và|and|,)\s*/i);
                parts.forEach(part => {
                    if(part.trim()) {
                        const clauses = generateMatchClauses(part, fields);
                        if (clauses.length > 0) targetMustArray.push({ "should": clauses });
                    }
                });
            }
        });
    }

    // =====================================================================
    // 2. MAIN LOGIC
    // =====================================================================

    let vector = $json.query_vector || $json.vector;
    if (!vector || vector.length === 0) { vector = new Array(1536).fill(0); }

    let aiJson = {};
    try {
        // Cố gắng lấy JSON từ nhiều nguồn khác nhau để tránh lỗi
        const rawSource = $('message refined').item.json || $json; 
        aiJson = rawSource.parsed_json || rawSource.output || rawSource || {};
        if (typeof aiJson === 'string') { try { aiJson = JSON.parse(aiJson); } catch(e) {} }
    } catch (e) { aiJson = {}; }

    let mustConditions = [];
    let isNameSearchMode = false;

    // ---------------------------------------------------------------------
    // [FIX QUAN TRỌNG] BẮT ĐÚNG BIẾN filter_candidate_name
    // ---------------------------------------------------------------------
    // Kiểm tra cả 2 biến để an toàn: filter_candidate_name HOẶC filter_name
    const nameInput = aiJson.filter_candidate_name || aiJson.filter_name;

    if (nameInput) {
        const nameClauses = generateNameClauses(nameInput);

        if (nameClauses.length > 0) {
            isNameSearchMode = true;
            mustConditions.push({ "should": nameClauses });
        }
    }

    // Nếu KHÔNG tìm tên, mới chạy các bộ lọc khác
    if (!isNameSearchMode) {

        // 1. KINH NGHIỆM
        if (aiJson.filter_experience && aiJson.filter_experience !== "[null]") {
            let expStr = String(aiJson.filter_experience).toLowerCase().trim();
            // Chỉ chạy nếu không phải là null
            if (expStr !== "null") {
                let operator = "gte"; 
                if (expStr.includes("<") || expStr.includes("dưới")) operator = "lte"; 

                const numberMatch = expStr.match(/(\d+(?:[.,]\d+)?)/);
                if (numberMatch) {
                    const number = parseFloat(numberMatch[1].replace(',', '.'));
                    let rangeQuery = {};
                    if (expStr.includes(">=")) rangeQuery = { "gte": number };
                    else if (expStr.includes("<=")) rangeQuery = { "lte": number };
                    else rangeQuery[operator] = number;

                    mustConditions.push({ "key": "experience_years", "range": rangeQuery });
                }
            }
        }

        // 2. SKILLS / COMPANY
        const universalFields = ["skills_list", "certificate", "education", "school", "major", "text", "role"];
        let combinedCompetencies = [];

        // Helper để check null array
        const isValidFilter = (val) => val && val !== "[null]" && (!Array.isArray(val) || val[0] !== null);

        if (isValidFilter(aiJson.filter_skills)) {
            combinedCompetencies.push(...(Array.isArray(aiJson.filter_skills) ? aiJson.filter_skills : [aiJson.filter_skills]));
        }
        if (isValidFilter(aiJson.filter_education)) {
            combinedCompetencies.push(...(Array.isArray(aiJson.filter_education) ? aiJson.filter_education : [aiJson.filter_education]));
        }

        combinedCompetencies = [...new Set(combinedCompetencies)].filter(item => item && item !== "null");
        if (combinedCompetencies.length > 0) processLogicFilter(combinedCompetencies, universalFields, mustConditions);

        if (isValidFilter(aiJson.filter_company)) {
            const companies = Array.isArray(aiJson.filter_company) ? aiJson.filter_company : [aiJson.filter_company];
            processLogicFilter(companies, ["company", "text"], mustConditions);
        }
    }

    // =========================================================
    // CẤU HÌNH OUTPUT
    // =========================================================

    let finalLimit = 50; 
    let finalThreshold = 0.6;

    // Chế độ tìm tên: Tắt threshold, tăng limit
    if (isNameSearchMode) {
        finalThreshold = 0.0; 
        finalLimit = 200; 
    } else if (mustConditions.length > 0) {
        finalThreshold = 0.0; 
    }

    let body = {
      "vector": vector,
      "limit": finalLimit,      
      "with_payload": true,
      "group_by": "candidate_id", 
      "group_size": 1 
    };

    if (!isNameSearchMode && mustConditions.length === 0) {
         if ($json.score_threshold !== undefined) finalThreshold = $json.score_threshold;
         body.score_threshold = finalThreshold;
    }

    if (mustConditions.length > 0) {
      body.filter = { "must": mustConditions };
    }

    return JSON.stringify(body);
  })()
}}

